#include <bits/stdc++.h>
using namespace std;

int minConferenceRooms(vector<int>& start, vector<int>& end, int n) {
    // Sort start and end times separately
    sort(start.begin(), start.end());
    sort(end.begin(), end.end());

    int rooms = 0;      // current rooms in use
    int maxRooms = 0;   // maximum rooms needed
    int i = 0, j = 0;   // pointers for start and end times

    while(i < n && j < n) {
        // If next start time is before next end time
        if(start[i] < end[j]) {
            rooms++;        // need new room
            i++;           // move to next start time
        }
        // If meeting ends
        else if(start[i] >= end[j]) {
            rooms--;       // free up a room
            j++;          // move to next end time
        }
        maxRooms = max(maxRooms, rooms);
    }

    return maxRooms;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n;
        cin >> n;

        vector<int> start(n), end(n);

        // Input start times
        for(int i = 0; i < n; i++) {
            cin >> start[i];
        }

        // Input end times
        for(int i = 0; i < n; i++) {
            cin >> end[i];
        }

        cout << minConferenceRooms(start, end, n) << endl;
    }

    return 0;
}
